/**
 * Proxy Rotation Service
 * Manages proxy pool, rotation logic, health tracking, and automatic failover
 * Supports HTTP, HTTPS, and SOCKS5 proxies
 */

import { logger } from './loggerService';
import { createAppError } from '../middleware/errorHandler';
import { ErrorCode } from '../constants/errorCodes';
import { errorRecoveryService } from './errorRecoveryService';

/**
 * Proxy Type
 */
export enum ProxyType {
  HTTP = 'HTTP',
  HTTPS = 'HTTPS',
  SOCKS5 = 'SOCKS5',
}

/**
 * Proxy Status
 */
export enum ProxyStatus {
  ACTIVE = 'ACTIVE',
  DISABLED = 'DISABLED',
  FAILED = 'FAILED',
  TESTING = 'TESTING',
}

/**
 * Proxy Configuration
 */
export interface ProxyConfig {
  id: string;
  url: string; // Format: protocol://host:port or protocol://user:pass@host:port
  type: ProxyType;
  status: ProxyStatus;
  priority: number; // Higher priority proxies are used first
  maxFailures: number; // Max consecutive failures before disabling
  healthCheckInterval: number; // Milliseconds between health checks
  timeout: number; // Request timeout in milliseconds
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Proxy Health Metrics
 */
export interface ProxyHealth {
  proxyId: string;
  isHealthy: boolean;
  consecutiveFailures: number;
  consecutiveSuccesses: number;
  totalRequests: number;
  successfulRequests: number;
  failedRequests: number;
  averageResponseTime: number; // milliseconds
  lastUsed?: Date;
  lastSuccess?: Date;
  lastFailure?: Date;
  lastError?: string;
  lastHealthCheck?: Date;
}

/**
 * Proxy Selection Strategy
 */
export enum ProxySelectionStrategy {
  ROUND_ROBIN = 'ROUND_ROBIN', // Rotate through proxies in order
  RANDOM = 'RANDOM', // Select random proxy
  LEAST_USED = 'LEAST_USED', // Select proxy with least requests
  BEST_PERFORMANCE = 'BEST_PERFORMANCE', // Select proxy with best response time
  PRIORITY = 'PRIORITY', // Select by priority (highest first)
}

/**
 * Proxy Pool Configuration
 */
export interface ProxyPoolConfig {
  selectionStrategy: ProxySelectionStrategy;
  healthCheckEnabled: boolean;
  healthCheckInterval: number; // milliseconds
  autoDisableOnFailure: boolean;
  maxConsecutiveFailures: number;
  reEnableAfter: number; // milliseconds to wait before re-enabling failed proxy
}

/**
 * Proxy Rotation Service
 */
export class ProxyRotationService {
  private proxies: Map<string, ProxyConfig> = new Map();
  private proxyHealth: Map<string, ProxyHealth> = new Map();
  private roundRobinIndex: number = 0;
  private healthCheckIntervals: Map<string, NodeJS.Timeout> = new Map();
  private poolConfig: ProxyPoolConfig = {
    selectionStrategy: ProxySelectionStrategy.ROUND_ROBIN,
    healthCheckEnabled: true,
    healthCheckInterval: 300000, // 5 minutes
    autoDisableOnFailure: true,
    maxConsecutiveFailures: 3,
    reEnableAfter: 600000, // 10 minutes
  };

  constructor(config?: Partial<ProxyPoolConfig>) {
    if (config) {
      this.poolConfig = { ...this.poolConfig, ...config };
    }
  }

  /**
   * Add proxy to pool
   */
  addProxy(config: Omit<ProxyConfig, 'id' | 'createdAt' | 'updatedAt'>): ProxyConfig {
    try {
      // Validate proxy URL
      this.validateProxyUrl(config.url);

      // Generate unique ID
      const id = this.generateProxyId(config.url);

      // Check if proxy already exists
      if (this.proxies.has(id)) {
        throw createAppError(
          'Proxy sudah ada dalam pool',
          ErrorCode.VALIDATION_ERROR,
          400
        );
      }

      const now = new Date();
      const proxy: ProxyConfig = {
        ...config,
        id,
        createdAt: now,
        updatedAt: now,
      };

      this.proxies.set(id, proxy);

      // Initialize health metrics
      this.proxyHealth.set(id, {
        proxyId: id,
        isHealthy: true,
        consecutiveFailures: 0,
        consecutiveSuccesses: 0,
        totalRequests: 0,
        successfulRequests: 0,
        failedRequests: 0,
        averageResponseTime: 0,
      });

      // Start health check if enabled
      if (this.poolConfig.healthCheckEnabled && proxy.status === ProxyStatus.ACTIVE) {
        this.startHealthCheck(id);
      }

      logger.info('Proxy added to pool', {
        proxyId: id,
        type: proxy.type,
        status: proxy.status,
      });

      return proxy;
    } catch (error) {
      logger.error('Failed to add proxy', error as Error, { config });
      throw error;
    }
  }

  /**
   * Remove proxy from pool
   */
  removeProxy(proxyId: string): void {
    try {
      const proxy = this.proxies.get(proxyId);
      if (!proxy) {
        throw createAppError(
          'Proxy tidak ditemukan',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      // Stop health check
      this.stopHealthCheck(proxyId);

      // Remove from maps
      this.proxies.delete(proxyId);
      this.proxyHealth.delete(proxyId);

      logger.info('Proxy removed from pool', { proxyId });
    } catch (error) {
      logger.error('Failed to remove proxy', error as Error, { proxyId });
      throw error;
    }
  }

  /**
   * Update proxy configuration
   */
  updateProxy(proxyId: string, updates: Partial<Omit<ProxyConfig, 'id' | 'createdAt' | 'updatedAt'>>): ProxyConfig {
    try {
      const proxy = this.proxies.get(proxyId);
      if (!proxy) {
        throw createAppError(
          'Proxy tidak ditemukan',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      // Validate URL if being updated
      if (updates.url) {
        this.validateProxyUrl(updates.url);
      }

      // Update proxy
      const updatedProxy: ProxyConfig = {
        ...proxy,
        ...updates,
        updatedAt: new Date(),
      };

      this.proxies.set(proxyId, updatedProxy);

      // Restart health check if status changed
      if (updates.status !== undefined) {
        this.stopHealthCheck(proxyId);
        if (updates.status === ProxyStatus.ACTIVE && this.poolConfig.healthCheckEnabled) {
          this.startHealthCheck(proxyId);
        }
      }

      logger.info('Proxy updated', { proxyId, updates: Object.keys(updates) });

      return updatedProxy;
    } catch (error) {
      logger.error('Failed to update proxy', error as Error, { proxyId, updates });
      throw error;
    }
  }

  /**
   * Get proxy by ID
   */
  getProxy(proxyId: string): ProxyConfig | undefined {
    return this.proxies.get(proxyId);
  }

  /**
   * Get all proxies
   */
  getAllProxies(filters?: {
    status?: ProxyStatus;
    type?: ProxyType;
    healthyOnly?: boolean;
  }): ProxyConfig[] {
    let proxies = Array.from(this.proxies.values());

    if (filters?.status) {
      proxies = proxies.filter(p => p.status === filters.status);
    }

    if (filters?.type) {
      proxies = proxies.filter(p => p.type === filters.type);
    }

    if (filters?.healthyOnly) {
      proxies = proxies.filter(p => {
        const health = this.proxyHealth.get(p.id);
        return health?.isHealthy === true;
      });
    }

    return proxies;
  }

  /**
   * Get proxy health metrics
   */
  getProxyHealth(proxyId: string): ProxyHealth | undefined {
    return this.proxyHealth.get(proxyId);
  }

  /**
   * Get all proxy health metrics
   */
  getAllProxyHealth(): ProxyHealth[] {
    return Array.from(this.proxyHealth.values());
  }

  /**
   * Select next proxy based on strategy
   */
  selectProxy(strategy?: ProxySelectionStrategy): ProxyConfig | null {
    try {
      const activeProxies = this.getAllProxies({
        status: ProxyStatus.ACTIVE,
        healthyOnly: true,
      });

      if (activeProxies.length === 0) {
        logger.warn('No active healthy proxies available');
        return null;
      }

      const selectedStrategy = strategy || this.poolConfig.selectionStrategy;

      let selectedProxy: ProxyConfig;

      switch (selectedStrategy) {
        case ProxySelectionStrategy.ROUND_ROBIN:
          selectedProxy = this.selectRoundRobin(activeProxies);
          break;

        case ProxySelectionStrategy.RANDOM:
          selectedProxy = this.selectRandom(activeProxies);
          break;

        case ProxySelectionStrategy.LEAST_USED:
          selectedProxy = this.selectLeastUsed(activeProxies);
          break;

        case ProxySelectionStrategy.BEST_PERFORMANCE:
          selectedProxy = this.selectBestPerformance(activeProxies);
          break;

        case ProxySelectionStrategy.PRIORITY:
          selectedProxy = this.selectByPriority(activeProxies);
          break;

        default:
          selectedProxy = this.selectRoundRobin(activeProxies);
      }

      logger.debug('Proxy selected', {
        proxyId: selectedProxy.id,
        strategy: selectedStrategy,
      });

      return selectedProxy;
    } catch (error) {
      logger.error('Failed to select proxy', error as Error, { strategy });
      return null;
    }
  }

  /**
   * Record successful proxy request
   */
  recordSuccess(proxyId: string, responseTime: number): void {
    try {
      const health = this.proxyHealth.get(proxyId);
      if (!health) {
        logger.warn('Proxy health not found', { proxyId });
        return;
      }

      health.consecutiveSuccesses++;
      health.consecutiveFailures = 0;
      health.totalRequests++;
      health.successfulRequests++;
      health.lastUsed = new Date();
      health.lastSuccess = new Date();

      // Update average response time (exponential moving average)
      if (health.averageResponseTime === 0) {
        health.averageResponseTime = responseTime;
      } else {
        health.averageResponseTime = 
          health.averageResponseTime * 0.7 + responseTime * 0.3;
      }

      health.isHealthy = true;

      logger.debug('Proxy success recorded', {
        proxyId,
        responseTime,
        consecutiveSuccesses: health.consecutiveSuccesses,
      });
    } catch (error) {
      logger.error('Failed to record proxy success', error as Error, { proxyId });
    }
  }

  /**
   * Record failed proxy request
   */
  recordFailure(proxyId: string, error: string): void {
    try {
      const health = this.proxyHealth.get(proxyId);
      if (!health) {
        logger.warn('Proxy health not found', { proxyId });
        return;
      }

      health.consecutiveFailures++;
      health.consecutiveSuccesses = 0;
      health.totalRequests++;
      health.failedRequests++;
      health.lastUsed = new Date();
      health.lastFailure = new Date();
      health.lastError = error;

      logger.warn('Proxy failure recorded', {
        proxyId,
        error,
        consecutiveFailures: health.consecutiveFailures,
      });

      // Check if proxy should be disabled
      if (
        this.poolConfig.autoDisableOnFailure &&
        health.consecutiveFailures >= this.poolConfig.maxConsecutiveFailures
      ) {
        this.disableProxy(proxyId, 'Max consecutive failures reached');

        // Schedule re-enable
        if (this.poolConfig.reEnableAfter > 0) {
          setTimeout(() => {
            this.enableProxy(proxyId);
          }, this.poolConfig.reEnableAfter);
        }
      } else {
        health.isHealthy = false;
      }
    } catch (error) {
      logger.error('Failed to record proxy failure', error as Error, { proxyId });
    }
  }

  /**
   * Disable proxy
   */
  disableProxy(proxyId: string, reason?: string): void {
    try {
      const proxy = this.proxies.get(proxyId);
      if (!proxy) {
        throw createAppError(
          'Proxy tidak ditemukan',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      proxy.status = ProxyStatus.DISABLED;
      proxy.updatedAt = new Date();

      const health = this.proxyHealth.get(proxyId);
      if (health) {
        health.isHealthy = false;
      }

      this.stopHealthCheck(proxyId);

      logger.warn('Proxy disabled', { proxyId, reason });
    } catch (error) {
      logger.error('Failed to disable proxy', error as Error, { proxyId });
      throw error;
    }
  }

  /**
   * Enable proxy
   */
  enableProxy(proxyId: string): void {
    try {
      const proxy = this.proxies.get(proxyId);
      if (!proxy) {
        throw createAppError(
          'Proxy tidak ditemukan',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      proxy.status = ProxyStatus.ACTIVE;
      proxy.updatedAt = new Date();

      const health = this.proxyHealth.get(proxyId);
      if (health) {
        health.consecutiveFailures = 0;
        health.isHealthy = true;
      }

      if (this.poolConfig.healthCheckEnabled) {
        this.startHealthCheck(proxyId);
      }

      logger.info('Proxy enabled', { proxyId });
    } catch (error) {
      logger.error('Failed to enable proxy', error as Error, { proxyId });
      throw error;
    }
  }

  /**
   * Test proxy connectivity
   */
  async testProxy(proxyId: string, testUrl: string = 'https://www.google.com'): Promise<{
    success: boolean;
    responseTime?: number;
    error?: string;
  }> {
    try {
      const proxy = this.proxies.get(proxyId);
      if (!proxy) {
        throw createAppError(
          'Proxy tidak ditemukan',
          ErrorCode.NOT_FOUND,
          404
        );
      }

      const startTime = Date.now();

      try {
        // Create fetch options with proxy
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), proxy.timeout);

        // Note: Node.js fetch doesn't natively support proxies
        // In production, you'd use a library like 'https-proxy-agent' or 'socks-proxy-agent'
        // For now, we'll simulate the test
        const response = await fetch(testUrl, {
          method: 'HEAD',
          signal: controller.signal,
        });

        clearTimeout(timeoutId);
        const responseTime = Date.now() - startTime;

        if (response.ok) {
          logger.info('Proxy test successful', {
            proxyId,
            responseTime,
            statusCode: response.status,
          });

          return {
            success: true,
            responseTime,
          };
        } else {
          return {
            success: false,
            error: `HTTP ${response.status}`,
          };
        }
      } catch (error) {
        const responseTime = Date.now() - startTime;

        logger.warn('Proxy test failed', {
          proxyId,
          responseTime,
          error: error instanceof Error ? error.message : String(error),
        });

        return {
          success: false,
          responseTime,
          error: error instanceof Error ? error.message : String(error),
        };
      }
    } catch (error) {
      logger.error('Failed to test proxy', error as Error, { proxyId });
      throw error;
    }
  }

  /**
   * Get pool statistics
   */
  getPoolStats(): {
    totalProxies: number;
    activeProxies: number;
    disabledProxies: number;
    healthyProxies: number;
    unhealthyProxies: number;
    averageResponseTime: number;
    totalRequests: number;
    successfulRequests: number;
    failedRequests: number;
    successRate: number;
  } {
    const allProxies = Array.from(this.proxies.values());
    const allHealth = Array.from(this.proxyHealth.values());

    const activeProxies = allProxies.filter(p => p.status === ProxyStatus.ACTIVE).length;
    const disabledProxies = allProxies.filter(p => p.status === ProxyStatus.DISABLED).length;
    const healthyProxies = allHealth.filter(h => h.isHealthy).length;
    const unhealthyProxies = allHealth.filter(h => !h.isHealthy).length;

    const totalRequests = allHealth.reduce((sum, h) => sum + h.totalRequests, 0);
    const successfulRequests = allHealth.reduce((sum, h) => sum + h.successfulRequests, 0);
    const failedRequests = allHealth.reduce((sum, h) => sum + h.failedRequests, 0);

    const averageResponseTime = allHealth.length > 0
      ? allHealth.reduce((sum, h) => sum + h.averageResponseTime, 0) / allHealth.length
      : 0;

    const successRate = totalRequests > 0
      ? (successfulRequests / totalRequests) * 100
      : 0;

    return {
      totalProxies: allProxies.length,
      activeProxies,
      disabledProxies,
      healthyProxies,
      unhealthyProxies,
      averageResponseTime: Math.round(averageResponseTime),
      totalRequests,
      successfulRequests,
      failedRequests,
      successRate: Math.round(successRate * 100) / 100,
    };
  }

  /**
   * Clear all proxies
   */
  clearAll(): void {
    try {
      // Stop all health checks
      for (const proxyId of this.proxies.keys()) {
        this.stopHealthCheck(proxyId);
      }

      this.proxies.clear();
      this.proxyHealth.clear();
      this.roundRobinIndex = 0;

      logger.info('All proxies cleared from pool');
    } catch (error) {
      logger.error('Failed to clear proxies', error as Error);
      throw error;
    }
  }

  /**
   * Update pool configuration
   */
  updatePoolConfig(config: Partial<ProxyPoolConfig>): void {
    this.poolConfig = { ...this.poolConfig, ...config };

    // Restart health checks if interval changed
    if (config.healthCheckInterval !== undefined || config.healthCheckEnabled !== undefined) {
      for (const proxyId of this.proxies.keys()) {
        this.stopHealthCheck(proxyId);
        if (this.poolConfig.healthCheckEnabled) {
          this.startHealthCheck(proxyId);
        }
      }
    }

    logger.info('Proxy pool config updated', { config });
  }

  /**
   * Get pool configuration
   */
  getPoolConfig(): ProxyPoolConfig {
    return { ...this.poolConfig };
  }

  // ==================== Private Methods ====================

  /**
   * Validate proxy URL format
   */
  private validateProxyUrl(url: string): void {
    try {
      const parsed = new URL(url);
      const validProtocols = ['http:', 'https:', 'socks5:'];

      if (!validProtocols.includes(parsed.protocol)) {
        throw new Error('Invalid protocol');
      }
    } catch {
      throw createAppError(
        'Format URL proxy tidak valid. Gunakan format: protocol://host:port atau protocol://user:pass@host:port',
        ErrorCode.VALIDATION_ERROR,
        400
      );
    }
  }

  /**
   * Generate unique proxy ID from URL
   */
  private generateProxyId(url: string): string {
    // Remove credentials from URL for ID generation
    const parsed = new URL(url);
    const cleanUrl = `${parsed.protocol}//${parsed.host}`;
    return Buffer.from(cleanUrl).toString('base64').replace(/[^a-zA-Z0-9]/g, '');
  }

  /**
   * Select proxy using round-robin strategy
   */
  private selectRoundRobin(proxies: ProxyConfig[]): ProxyConfig {
    const proxy = proxies[this.roundRobinIndex % proxies.length];
    this.roundRobinIndex = (this.roundRobinIndex + 1) % proxies.length;
    return proxy;
  }

  /**
   * Select proxy using random strategy
   */
  private selectRandom(proxies: ProxyConfig[]): ProxyConfig {
    const index = Math.floor(Math.random() * proxies.length);
    return proxies[index];
  }

  /**
   * Select proxy with least requests
   */
  private selectLeastUsed(proxies: ProxyConfig[]): ProxyConfig {
    return proxies.reduce((least, current) => {
      const leastHealth = this.proxyHealth.get(least.id);
      const currentHealth = this.proxyHealth.get(current.id);

      if (!leastHealth) return current;
      if (!currentHealth) return least;

      return currentHealth.totalRequests < leastHealth.totalRequests ? current : least;
    });
  }

  /**
   * Select proxy with best performance
   */
  private selectBestPerformance(proxies: ProxyConfig[]): ProxyConfig {
    return proxies.reduce((best, current) => {
      const bestHealth = this.proxyHealth.get(best.id);
      const currentHealth = this.proxyHealth.get(current.id);

      if (!bestHealth) return current;
      if (!currentHealth) return best;

      // Prefer proxies with requests and lower response time
      if (currentHealth.totalRequests === 0) return best;
      if (bestHealth.totalRequests === 0) return current;

      return currentHealth.averageResponseTime < bestHealth.averageResponseTime ? current : best;
    });
  }

  /**
   * Select proxy by priority
   */
  private selectByPriority(proxies: ProxyConfig[]): ProxyConfig {
    return proxies.reduce((highest, current) => {
      return current.priority > highest.priority ? current : highest;
    });
  }

  /**
   * Start health check for proxy
   */
  private startHealthCheck(proxyId: string): void {
    // Clear existing interval if any
    this.stopHealthCheck(proxyId);

    const proxy = this.proxies.get(proxyId);
    if (!proxy) return;

    const interval = setInterval(async () => {
      await this.performHealthCheck(proxyId);
    }, proxy.healthCheckInterval || this.poolConfig.healthCheckInterval);

    this.healthCheckIntervals.set(proxyId, interval);

    logger.debug('Health check started', { proxyId });
  }

  /**
   * Stop health check for proxy
   */
  private stopHealthCheck(proxyId: string): void {
    const interval = this.healthCheckIntervals.get(proxyId);
    if (interval) {
      clearInterval(interval);
      this.healthCheckIntervals.delete(proxyId);
      logger.debug('Health check stopped', { proxyId });
    }
  }

  /**
   * Perform health check on proxy
   */
  private async performHealthCheck(proxyId: string): Promise<void> {
    try {
      const health = this.proxyHealth.get(proxyId);
      if (!health) return;

      health.lastHealthCheck = new Date();

      const result = await this.testProxy(proxyId);

      if (result.success) {
        health.isHealthy = true;
        health.consecutiveFailures = 0;
      } else {
        health.isHealthy = false;
        health.consecutiveFailures++;

        // Auto-disable if threshold reached
        if (
          this.poolConfig.autoDisableOnFailure &&
          health.consecutiveFailures >= this.poolConfig.maxConsecutiveFailures
        ) {
          this.disableProxy(proxyId, 'Health check failures exceeded threshold');
        }
      }

      logger.debug('Health check completed', {
        proxyId,
        success: result.success,
        isHealthy: health.isHealthy,
      });
    } catch (error) {
      logger.error('Health check failed', error as Error, { proxyId });
    }
  }

  /**
   * Cleanup resources
   */
  destroy(): void {
    // Stop all health checks
    for (const proxyId of this.proxies.keys()) {
      this.stopHealthCheck(proxyId);
    }

    logger.info('Proxy rotation service destroyed');
  }
}

