            }

            proxyRotationService.addProxy({
              url: proxyUrl,
              type: proxyType,
              status: ProxyStatus.ACTIVE,
              priority: source.proxies.length - i, // Higher priority for earlier proxies
              maxFailures: 3,
              healthCheckInterval: 300000, // 5 minutes
              timeout: source.timeout || 30000,
            });

            logger.info('Proxy added to pool for source', {
              sourceId,
              proxyUrl: proxyUrl.replace(/\/\/.*@/, '//***@'), // Hide credentials in logs
            });
          } catch (error) {
            logger.warn('Failed to add proxy to pool', {
              sourceId,
              proxyUrl: proxyUrl.replace(/\/\/.*@/, '//***@'),
