          logger.info('Single proxy added to pool for source', {
            sourceId,
            proxyUrl: source.proxy.replace(/\/\/.*@/, '//***@'),
          });
        } catch (error) {
          logger.warn('Failed to add single proxy to pool', {
            sourceId,
            error: error instanceof Error ? error.message : String(error),
          });
        }
      }
    } catch (error) {
      logger.error('Failed to initialize proxy pool', error as Error, { sourceId });
    }
